var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 바람대로 와일러는 다시 감옥에 수감되었네.","JPN":"君の望み通り、ワイラーは再び刑務所に収監された。","ENG":"Wyler's been put back into jail, just like you wanted.","TWN":"如你所願，瓦勒被重新收監了。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조니 앤 멜로니도 이번에는 쉽게 그 자를 빼낼 수 없을 거야.","JPN":"ジョニー＆メロニーでも、今度はそう簡単に刑務所から出すことはできないだろう。","ENG":"Even Jonie & Melonie will have a hard time getting him out now.","TWN":"這次，就算是喬尼&梅洛尼也應該很難把他弄出來。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 애초에 이젠 스폰서들이 그 자를 찾을 이유가 없겠지.","JPN":"いや、そもそも、もう彼を欲しがる理由がない。","ENG":"No, better yet, there won't be a reason for sponsors to hire him anymore.","TWN":"不，以後贊助商都沒有理由需要他了。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잠시 자리를 피해주겠네.","JPN":"少し一人になった方がいいだろう。","ENG":"I'll let you have a minute.","TWN":"我暫時離開一下吧。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"감사합니다. 사장님.","JPN":"ありがとうございます。社長。","ENG":"Thank you, Boss.","TWN":"謝謝你，老闆。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"흐윽…… 흑…….","JPN":"うっ……ううっ……","ENG":"*Sniffle...* Hnnggh...","TWN":"嗚嗚……嗚……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"유명한 여배우를 여기서 만나게 될 줄은 몰랐는데.","JPN":"こんなところで大女優に会うとはな。","ENG":"I never thought I'd encounter a famous actress here.","TWN":"沒想到會在這裡遇到著名女影星啊。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 기억하고 있어요.","JPN":"あなたを覚えています。","ENG":"I remember you.","TWN":"我記得你。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"첫 만남은 기자들 때문에 소란스러웠는데, 지금은 무척 고요하네요.","JPN":"初対面のときは記者がいてうるさかったですが、今はとても静かですね。","ENG":"The first time we met, it was so loud with all those reporters. But now, it is silent.","TWN":"第一次見面的時候因為記者的關係，環境不是很好。現在這種安靜的氛圍正適合。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 어째선지 자네가 낯설지 않군.","JPN":"私も何だか君に馴染みがある。","ENG":"For some reason, I also believe we have met before.","TWN":"不知為何，我也對你並不陌生。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여기는 본래 대정화 전쟁의 전몰자 묘역이라네.","JPN":"ここは本来大浄化戦争の戦没者の墓地だった。","ENG":"This place originally used to be a graveyard for those who died in the Grand Purification War.","TWN":"這裡原本是淨化之戰戰亡者的陵園。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죽은 가족들 곁에 묻히고 싶어하는 이들 때문에 주위에 일반 묘역이 생겨났지.","JPN":"亡くなった家族のそばに葬られたいという者たちのために、周りには一般墓地が作られた。","ENG":"However, because some people preferred to be buried near their families, a second general-use graveyard was built nearby.","TWN":"因為大多人的遺願是被葬在死去的家人身旁，所以周圍又多了很多普通墓地。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 가족 중에도 전쟁 중에 희생된 분이 계시나?","JPN":"君の家族にも戦争で亡くなった方がいるのか？","ENG":"Do you happen to have a family member who died in the war by chance?","TWN":"怎麼，你也有在戰爭中犧牲的親人嗎？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 그저 희생된 이들에게 애도를 표하고 싶었을 뿐입니다.","JPN":"いいえ。私はただ犠牲になった方々への哀悼の意を表したかっただけです。","ENG":"No. I am here to express my condolences to those who sacrificed their lives.","TWN":"不，我只是想向犧牲的人們表示哀悼而已。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"준결승전은 잘 봤습니다. 부족한 병사들을 잘 지휘해 주시더군요.","JPN":"準決勝戦を見ました。欠点の多いメンバーたちを見事に指揮しておられましたね。","ENG":"I enjoyed watching the semifinal match. You commanded those inept soldiers quite well.","TWN":"半決賽我看了，你很會指揮實力不足的士兵。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네, 하지만 그렇게 보였다면 부족한 부분을 채워 주지 못한 내 잘못이겠지.","JPN":"そうか、感謝する。しかしそう見えていたのなら、その欠点をなんとかしてやれなかった私の責任だろう。","ENG":"Thank you. But if you could see that they were inept, then it's my fault that I couldn't do better.","TWN":"多謝誇獎。不過如果他們顯得實力不足，那還是我的錯，我沒能彌補他們的不足之處。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그동안 수많은 사건을 해결해 오면서 한가지 깨달은 게 있어.","JPN":"今まで様々な事件を解決してきて、気づいたことがあるんだ。","ENG":"After solving countless cases, there is one thing that I came to realize.","TWN":"在解決了無數案件的過程中，我明白了一件事。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리의 운명이라는 보이지 않는 실타래 속에는 사실, 선홍색의 실이 얽혀 있다는 걸.","JPN":"私たちの運命という目に見えない糸には、深紅に染まった糸が絡まっている。","ENG":"It's that within the invisible threads of destiny, our fates are actually intertwined by a bright red thread.","TWN":"在我們那個名為命運的無形線團裡，其實還纏繞著一根鮮紅色的細線。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언뜻 보면, 전혀 상관없는 것들이……. 복잡하게 얽히고 얽혀 어떤 사건을 만들어 내지.","JPN":"最初は何の関係もなく思えても……いつしか複雑に絡み合い、ある出来事を作り出す。","ENG":"The things that seem unrelated at first glance... get tangled together to create an event.","TWN":"乍一看，是完全無關的事物……複雜地交織在一起，才製造出了某種事件。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그것을 철저하고, 낱낱이 규명하는 것이 나의 업이라네.","JPN":"それを徹底的に、一つ残らず突き詰めることが私の仕事だ。","ENG":"My job is to thoroughly investigate and identify them.","TWN":"徹底而詳細地查明這些，就是我的職責。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……책임감이 과하면 독이 되기 마련이죠.","JPN":"……強すぎる責任感は身を滅ぼします。","ENG":"...Too much responsibility can be poisonous.","TWN":"……過重的責任感，必定會成為毒藥。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};